abel>Target Hire</label><input id="line_target_hire_date" class="form-control date-field"></div><div class="col-md-2 form-group"><label>Recruitment Status</label><select id="line_recruitment_status" class="form-control"><option>NOT_STARTED</option><option>OPEN</option><option>IN_PROGRESS</option><option>OFFER</option><option>HIRED</option><option>CANCELLED</option></select></div></div><div class="row"><div class="col-md-2 form-group"><label>Monthly Cost</label><input id="line_estimated_monthly_cost" type="number" step="0.01" min="0" class="form-control" value="0"></div><div class="col-md-2 form-group"><label>Budget Amount</label><input id="line_budget_amount" type="number" step="0.01" min="0" class="form-control" value="0"></div><div class="col-md-4 form-group"><label>Reason</label><input id="line_reason" class="form-control"></div><div class="col-md-3 form-group"><label><?=hr_h('common_remarks', 'Remarks');?></label><input id="line_remarks" class="form-control"></div><div class="col-md-1 form-group"><label>&nbsp;</label><button type="button" id="btn_add_line_mp" class="btn btn-primary btn-block"><i class="fa fa-plus"></i></button></div></div></div>
