<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
var mpLines=[];
function mpError(m){$('.isi_warning_delete').text(m||'Manpower Planning gagal diproses.');$('.error_data_delete').fadeIn();}
function mpFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),planning_type:$('#filter_planning_type').val(),planning_status:$('#filter_planning_status').val(),department_code:$('#filter_department_code').val(),keyword:$('#filter_keyword').val()};}
function esc(s){return $('<div>').text(s||'').html();}
function mpSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function mpAjaxSelect(selector,act,placeholder,parent){$(selector).select2({width:'100%',allowClear:true,placeholder:placeholder,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
function loadNextNo(){ $.post('<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=next_no',{plan_year:$('#plan_year').val()},function(r){ if(r.status==='good')$('#plan_no').val(r.plan_no); },'json'); }
function resetMp(title){$('#form_mp')[0].reset();$('#mp_id').val('');$('#plan_year').val('<?=date('Y');?>');$('#period_from').val('<?=$defaultFrom;?>');$('#period_to').val('<?=$defaultTo;?>');$('#planning_type').val('ANNUAL').trigger('change');$('#planning_status').val('DRAFT').trigger('change');$('#budget_currency').val('IDR').trigger('change');$('#company_structure_id,#department_code,#cost_center_code,#profit_center_code,#approved_by_employee_id,#line_position_id,#line_job_title_id,#line_department_code').val(null).trigger('change');mpLines=[];renderLines();$('#modal_mp .modal-title').text(title||'Create Manpower Plan');loadNextNo();}
function clearLine(){mpSet('#line_position_id','','');mpSet('#line_job_title_id','','');mpSet('#line_department_code','','');$('#line_employee_group').val('STAFF').trigger('change');$('#line_pay_grade').val('');$('#line_current_headcount').val(0);$('#line_planned_headcount,#line_requested_headcount').val(1);$('#line_hire_type').val('NEW_HIRE').trigger('change');$('#line_priority').val('MEDIUM').trigger('change');$('#line_target_hire_date').val('');$('#line_recruitment_status').val('NOT_STARTED').trigger('change');$('#line_estimated_monthly_cost,#line_budget_amount').val(0);$('#line_reason,#line_remarks').val('');}
function renderLines(){var h='';mpLines.forEach(function(l,i){h+='<tr><td>'+(i+1)+'</td><td>'+esc(l.department_text||l.department_code)+'</td><td><b>'+esc(l.position_text||'-')+'</b><br><small>'+esc(l.job_title_text||'-')+'</small></td><td>'+esc(l.employee_group+' / '+(l.pay_grade||'-'))+'</td><td class="text-right">'+Number(l.current_headcount||0).toFixed(2)+'</td><td class="text-right">'+Number(l.planned_headcount||0).toFixed(2)+'</td><td class="text-right">'+Number(l.requested_headcount||0).toFixed(2)+'</td><td>'+esc(l.hire_type+' / '+l.priority)+'</td><td>'+esc(l.target_hire_date||'-')+'</td><td class="text-right">'+Number(l.budget_amount||0).toLocaleString()+'</td><td>'+esc(l.recruitment_status)+'</td><td><button type="button" class="btn btn-danger btn-xs btn-line-del" data-i="'+i+'"><i class="fa fa-trash"></i></button></td></tr>';});if(!h)h='<tr><td colspan="12" class="text-center text-muted">Belum ada detail requirement.</td></tr>';$('#mp_lines_table tbody').html(h);$('#lines_json').val(JSON.stringify(mpLines));}
function addLineFromForm(){var dept=$('#line_department_code').val(),pos=$('#line_position_id').val(),job=$('#line_job_title_id').val();if(!dept&&!pos&&!job){mpError('Detail wajib punya Department, Position, atau Job Title.');return;}var cur=parseFloat($('#line_current_headcount').val())||0,plan=parseFloat($('#line_planned_headcount').val())||0,req=parseFloat($('#line_requested_headcount').val())||Math.max(0,plan-cur),monthly=parseFloat($('#line_estimated_monthly_cost').val())||0,budget=parseFloat($('#line_budget_amount').val())||monthly*req*12;mpLines.push({department_code:dept,department_text:$('#line_department_code option:selected').text(),position_id:pos,position_text:$('#line_position_id option:selected').text(),job_title_id:job,job_title_text:$('#line_job_title_id option:selected').text(),employee_group:$('#line_employee_group').val(),pay_grade:$('#line_pay_grade').val(),current_headcount:cur,current_fte:cur,planned_headcount:plan,planned_fte:plan,requested_headcount:req,approved_headcount:0,hire_type:$('#line_hire_type').val(),priority:$('#line_priority').val(),target_hire_date:$('#line_target_hire_date').val(),estimated_monthly_cost:monthly,budget_amount:budget,recruitment_status:$('#line_recruitment_status').val(),reason:$('#line_reason').val(),remarks:$('#line_remarks').val()});renderLines();clearLine();}
$(function(){if($.fn.datepicker){$('.mp-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_planning_type,#filter_planning_status,#planning_type,#planning_status,#budget_currency,#line_employee_group,#line_hire_type,#line_priority,#line_recruitment_status').select2({width:'100%',allowClear:true});mpAjaxSelect('#filter_department_code','department_search','Semua Department');mpAjaxSelect('#company_structure_id','company_structure_search','Pilih Org Unit',$('#modal_mp'));mpAjaxSelect('#department_code','department_search','Pilih Department Scope',$('#modal_mp'));mpAjaxSelect('#cost_center_code','cost_center_search','Pilih Cost Center',$('#modal_mp'));mpAjaxSelect('#profit_center_code','profit_center_search','Pilih Profit Center',$('#modal_mp'));mpAjaxSelect('#approved_by_employee_id','employee_search','Pilih Approver',$('#modal_mp'));mpAjaxSelect('#line_position_id','position_search','Cari Position',$('#modal_mp'));mpAjaxSelect('#line_job_title_id','job_title_search','Cari Job Title',$('#modal_mp'));mpAjaxSelect('#line_department_code','department_search','Pilih Department',$('#modal_mp'));}
var dt=$('#dtb_manpower_planning').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[6,7,8],className:'text-right'},{width:'42px',targets:0},{width:'150px',targets:1}],ajax:{url:'<?=base_admin();?>modul/manpower_planning/manpower_planning_data.php',type:'post',data:function(d){$.extend(d,mpFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_submitted').text(k.submitted||0);$('#kpi_approved').text(k.approved||0);$('#kpi_requested_hc').text(k.requested_hc||0);$('#kpi_gap_hc').text(k.gap_hc||0);$('#kpi_budget').text(k.budget||0);return j.data||[];},error:function(xhr){console.log(xhr.responseText);mpError('Data Manpower Planning gagal dimuat.');}}});
$('#btn_open_mp').click(function(){resetMp('Create Manpower Plan');$('#modal_mp').modal({backdrop:'static',keyboard:false});});$('#btn_next_no,#plan_year').on('click change',loadNextNo);$('#btn_add_line_mp').click(addLineFromForm);$(document).on('click','.btn-line-del',function(){mpLines.splice(parseInt($(this).data('i'),10),1);renderLines();});
$('#line_position_id').on('select2:select',function(e){$.post('<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=position_info',{id:e.params.data.id},function(r){if(r.status!=='good')return;var d=r.data||{};mpSet('#line_department_code',d.department_code,d.department_text);mpSet('#line_job_title_id',d.job_title_id,d.job_title_text);$('#line_employee_group').val(d.employee_group||'STAFF').trigger('change');$('#line_pay_grade').val(d.pay_grade||'');$('#line_current_headcount').val(d.current_headcount||0);$('#line_planned_headcount').val(d.planned_headcount||1);$('#line_requested_headcount').val(Math.max(0,(parseFloat(d.planned_headcount)||0)-(parseFloat(d.current_headcount)||0)));},'json');});
$('#line_planned_headcount,#line_current_headcount,#line_requested_headcount,#line_estimated_monthly_cost').on('keyup change',function(){var cur=parseFloat($('#line_current_headcount').val())||0,plan=parseFloat($('#line_planned_headcount').val())||0,req=parseFloat($('#line_requested_headcount').val())||Math.max(0,plan-cur),monthly=parseFloat($('#line_estimated_monthly_cost').val())||0;if(!$('#line_requested_headcount').is(':focus'))$('#line_requested_headcount').val(Math.max(0,plan-cur));$('#line_budget_amount').val((monthly*req*12).toFixed(2));});
$('#btn_filter_mp').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_mp').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_planning_type,#filter_planning_status,#filter_department_code').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_mp').click(function(){window.location='<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=export&'+$.param(mpFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$('#form_mp').submit(function(e){e.preventDefault();renderLines();if(mpLines.length<1){mpError('Minimal satu detail manpower plan wajib diisi.');return;}var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Manpower Plan');if(r.status==='good'){$('#modal_mp').modal('hide');dt.draw(false);Swal.fire('Saved','Manpower Planning berhasil disimpan.','success');}else mpError(r.error_message);},'json').fail(function(xhr){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Manpower Plan');mpError(xhr.responseText);});});
$(document).on('click','.btn-mp-detail',function(){$.post('<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=detail',{id:$(this).data('id')},function(h){$('#mp_detail_body').html(h);$('#modal_mp_detail').modal('show');});});
$(document).on('click','.btn-mp-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=get',{id:id},function(r){if(r.status!=='good'){mpError(r.error_message);return;}resetMp('Edit Manpower Plan');var h=r.data||{};['id','plan_no','plan_name','plan_year','plan_version','period_from','period_to','approved_at','sap_reference','remarks'].forEach(function(k){$('#'+(k==='id'?'mp_id':k)).val(h[k]||'');});$('#planning_type').val(h.planning_type).trigger('change');$('#planning_status').val(h.planning_status).trigger('change');$('#budget_currency').val(h.budget_currency).trigger('change');mpSet('#company_structure_id',h.company_structure_id,h.company_structure_text);mpSet('#department_code',h.department_code,h.department_text);mpSet('#cost_center_code',h.cost_center_code,h.cost_center_text);mpSet('#profit_center_code',h.profit_center_code,h.profit_center_text);mpSet('#approved_by_employee_id',h.approved_by_employee_id,h.approved_by_text);mpLines=h.lines||[];renderLines();$('#modal_mp').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-mp-status',function(){var id=$(this).data('id'),status=$(this).data('status');$.post('<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Updated','Status berhasil diubah.','success');}else mpError(r.error_message);},'json');});
$(document).on('click','.btn-mp-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/manpower_planning/manpower_planning_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else mpError(r.error_message);},'json').fail(function(xhr){mpError(xhr.responseText);});});});
});
</script>
